"use strict";window.addEventListener("DOMContentLoaded",d=>{const e=document.body.querySelector("#sidebarToggle");if(e){const t=localStorage.getItem("sb|sidebar-toggle");t==="true"?document.body.classList.add("sb-sidenav-toggled"):t==="false"&&document.body.classList.remove("sb-sidenav-toggled"),e.addEventListener("click",s=>{s.preventDefault(),document.body.classList.toggle("sb-sidenav-toggled"),localStorage.setItem("sb|sidebar-toggle",document.body.classList.contains("sb-sidenav-toggled"))})}});
